import React, { useEffect, useRef, useState } from 'react';
import axios from 'axios';
import { io } from 'socket.io-client';
import { useNavigate } from 'react-router-dom';

const PRIMARY_BLUE = '#007BFF';

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [tutors, setTutors] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('overview');
  const [liveMessages, setLiveMessages] = useState([]);

  const socketRef = useRef(null);

  const token = typeof window !== 'undefined'
    ? localStorage.getItem('ethioBooksToken')
    : null;

  const api = axios.create({
    baseURL: 'http://localhost:5000/api',
    headers: token
      ? {
          Authorization: `Bearer ${token}`
        }
      : {}
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      setError('');

      const [pendingTutorsRes, pendingTxRes, usersRes] = await Promise.all([
        api.get('/admin/pending-tutors'),
        api.get('/admin/pending-transactions'),
        api.get('/admin/users')
      ]);

      setTutors(pendingTutorsRes.data || []);
      setTransactions(pendingTxRes.data || []);
      setUsers(usersRes.data || []);
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to load admin data.';
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!token) {
      setError('No admin token found. Please log in as admin.');
      setLoading(false);
      return;
    }

    fetchData();

    const socket = io('http://localhost:5000', {
      auth: { token }
    });

    socketRef.current = socket;

    socket.on('connect_error', (err) => {
      console.error('Socket connection error:', err.message);
    });

    socket.on('newMessage', (message) => {
      setLiveMessages((prev) => [message, ...prev].slice(0, 100));
    });

    return () => {
      socket.disconnect();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const totalStudents = users.filter((u) => u.role === 'student').length;
  const totalTutors = users.filter((u) => u.role === 'tutor').length;
  const pendingApprovals = tutors.length + transactions.length;

  const handleApproveTutor = async (id) => {
    try {
      await api.patch(`/admin/approve-tutor/${id}`);
      await fetchData();
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to approve tutor.';
      alert(message);
    }
  };

  const handleViewDocs = (docs = []) => {
    if (!docs || docs.length === 0) {
      alert('No documents uploaded for this tutor.');
      return;
    }
    // Open first document; you can extend this to show all
    window.open(docs[0], '_blank', 'noopener,noreferrer');
  };

  const handleApprovePremium = async (id) => {
    try {
      await api.patch(`/admin/approve-premium/${id}`);
      await fetchData();
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to approve premium.';
      alert(message);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('ethioBooksToken');
    localStorage.removeItem('ethioBooksUser');
    navigate('/');
  };

  return (
    <div className="min-h-screen bg-gray-50/50 text-base font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Header */}
      <header
        className="w-full bg-white shadow-sm sticky top-0 z-50 transition-shadow duration-300"
        style={{ borderBottom: '4px solid rgba(0,123,255,0.15)' }}
      >
        <div className="max-w-[1600px] mx-auto px-6 py-5 sm:px-10 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <h1
              className="text-3xl font-extrabold tracking-tight"
              style={{ color: PRIMARY_BLUE }}
            >
              Ethio Books
            </h1>
            <span className="hidden sm:inline-block px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-sm font-bold uppercase tracking-wider">
              Control Center
            </span>
          </div>
          <div className="flex items-center space-x-6">
            <div className="hidden sm:flex flex-col items-end">
              <span className="text-sm text-gray-500 font-medium">Logged in as</span>
              <span className="font-bold text-gray-900 leading-tight">System Admin</span>
            </div>
            <button
              type="button"
              onClick={handleLogout}
              className="px-6 py-2.5 text-sm font-bold rounded-xl border-2 border-gray-200 text-gray-700 hover:text-white hover:bg-gray-900 hover:border-gray-900 transition-all shadow-sm focus:outline-none focus:ring-4 focus:ring-gray-100"
            >
              Log out
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-[1600px] mx-auto px-6 sm:px-10 py-10 space-y-10">
        {error && (
          <div className="rounded-2xl border-2 border-red-200 bg-red-50 p-6 flex items-start space-x-4">
            <div className="flex-shrink-0 bg-red-100 rounded-full p-2">
              <svg className="w-6 h-6 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <div>
              <h3 className="text-red-800 font-bold text-lg">System Error</h3>
              <p className="text-red-700 mt-1">{error}</p>
            </div>
          </div>
        )}

        {/* Tab Navigation */}
        <div className="flex items-center space-x-2 border-b-2 border-gray-200 pb-px">
          <button
            type="button"
            onClick={() => setActiveTab('overview')}
            className={`px-6 py-4 text-lg font-bold transition-colors border-b-4 -mb-[2px] ${
              activeTab === 'overview'
                ? 'border-blue-600 text-blue-700 bg-blue-50/50 rounded-t-xl'
                : 'border-transparent text-gray-500 hover:text-gray-800 hover:bg-gray-50 rounded-t-xl'
            }`}
          >
            Dashboard Overview
          </button>
          <button
            type="button"
            onClick={() => setActiveTab('live')}
            className={`px-6 py-4 text-lg font-bold transition-colors border-b-4 -mb-[2px] relative ${
              activeTab === 'live'
                ? 'border-blue-600 text-blue-700 bg-blue-50/50 rounded-t-xl'
                : 'border-transparent text-gray-500 hover:text-gray-800 hover:bg-gray-50 rounded-t-xl'
            }`}
          >
            Live Feed Monitoring  
            {liveMessages.length > 0 && (
              <span className="absolute top-4 right-2 flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
              </span>
            )}
          </button>
        </div>

        {activeTab === 'overview' && (
          <div className="space-y-10 animate-fade-in">
            {/* Top Stats Cards */}
            <section className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {/* Total Students */}
              <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8 flex flex-col justify-between transition-transform hover:-translate-y-1 duration-300">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-bold tracking-widest text-gray-500 uppercase">
                    Total Students
                  </span>
                  <div className="w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 14l9-5-9-5-9 5 9 5z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 14l6.16-3.422a12.083 12.083 0 01.665 6.479A11.952 11.952 0 0012 20.055a11.952 11.952 0 00-6.824-2.998 12.078 12.078 0 01.665-6.479L12 14z" />
                    </svg>
                  </div>
                </div>
                <div className="mt-6">
                  <p className="text-5xl font-black text-gray-900 tracking-tight">
                    {loading ? '—' : totalStudents}
                  </p>
                </div>
              </div>

              {/* Total Tutors */}
              <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8 flex flex-col justify-between transition-transform hover:-translate-y-1 duration-300">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-bold tracking-widest text-gray-500 uppercase">
                    Total Tutors
                  </span>
                  <div className="w-12 h-12 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
                    </svg>
                  </div>
                </div>
                <div className="mt-6">
                  <p className="text-5xl font-black text-gray-900 tracking-tight">
                    {loading ? '—' : totalTutors}
                  </p>
                </div>
              </div>

              {/* Pending Approvals */}
              <div className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8 flex flex-col justify-between transition-transform hover:-translate-y-1 duration-300 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-50 rounded-bl-full -z-10 opacity-50"></div>
                <div className="flex items-center justify-between">
                  <span className="text-sm font-bold tracking-widest text-gray-500 uppercase">
                    Requires Action
                  </span>
                  <div className="w-12 h-12 bg-orange-50 text-orange-500 rounded-2xl flex items-center justify-center">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                    </svg>
                  </div>
                </div>
                <div className="mt-6 flex items-baseline space-x-3">
                  <p
                    className="text-5xl font-black tracking-tight"
                    style={{ color: PRIMARY_BLUE }}
                  >
                    {loading ? '—' : pendingApprovals}
                  </p>
                  <span className="text-lg font-medium text-gray-500">pending</span>
                </div>
              </div>
            </section>

            {/* Main Content Grid: Tutor Approvals + Empty Space */}
            <section className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              {/* Tutor Approval Table Container */}
              <div className="xl:col-span-2 bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-8 gap-4">
                  <div>
                    <h2 className="text-xl font-bold text-gray-900">
                      Tutor Registrations
                    </h2>
                    <p className="text-gray-500 mt-1">Review and approve new tutors.</p>
                  </div>
                  <span className="inline-flex items-center px-4 py-2 rounded-full bg-blue-50 text-blue-700 font-bold text-sm">
                    {tutors.length} Total Pending
                  </span>
                </div>

                <div className="overflow-x-auto rounded-xl border border-gray-100">
                  <table className="min-w-full text-left">
                    <thead className="bg-gray-50/80">
                      <tr className="text-gray-500 text-sm font-bold uppercase tracking-wider">
                        <th className="px-6 py-5 rounded-tl-xl">Applicant Name</th>
                        <th className="px-6 py-5">Education Background</th>
                        <th className="px-6 py-5">Application Status</th>
                        <th className="px-6 py-5 text-right rounded-tr-xl">Action Required</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {tutors.length === 0 && (
                        <tr>
                          <td
                            colSpan={4}
                            className="py-12 text-center text-gray-400 font-medium text-lg"
                          >
                            <div className="flex flex-col items-center justify-center space-y-3">
                              <svg className="w-12 h-12 text-gray-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                              <span>You're all caught up! No pending tutors.</span>
                            </div>
                          </td>
                        </tr>
                      )}
                      {tutors.map((tutor) => (
                        <tr
                          key={tutor._id}
                          className="hover:bg-blue-50/30 transition-colors"
                        >
                          <td className="px-6 py-5 whitespace-nowrap">
                            <div className="flex items-center">
                              <div className="h-10 w-10 flex-shrink-0 rounded-full bg-gradient-to-br from-blue-100 to-indigo-100 flex items-center justify-center text-blue-700 font-bold text-lg">
                                {tutor.fullName?.charAt(0) || 'U'}
                              </div>
                              <div className="ml-4">
                                <div className="text-base font-bold text-gray-900">{tutor.fullName}</div>
                                <div className="text-sm text-gray-500">{tutor.email || tutor.telegramUsername || 'No contact info'}</div>
                              </div>
                            </div>
                          </td>
                          <td className="px-6 py-5 text-gray-700 font-medium">
                            {tutor.educationLevel || <span className="text-gray-400 italic">Not provided</span>}
                          </td>
                          <td className="px-6 py-5">
                            <span className="inline-flex items-center gap-1.5 rounded-full bg-yellow-100 px-3 py-1 text-sm font-bold text-yellow-800">
                              <div className="w-1.5 h-1.5 rounded-full bg-yellow-500"></div>
                              {tutor.tutorStatus}
                            </span>
                          </td>
                          <td className="px-6 py-5 text-right whitespace-nowrap">
                            <div className="flex items-center justify-end space-x-3">
                              <button
                                type="button"
                                onClick={() => handleViewDocs(tutor.docs)}
                                className="px-4 py-2 text-sm font-bold rounded-xl border-2 border-gray-200 text-gray-700 hover:bg-gray-100 hover:text-gray-900 transition-colors focus:ring-4 focus:ring-gray-100"
                              >
                                View CV / Docs
                              </button>
                              <button
                                type="button"
                                onClick={() => handleApproveTutor(tutor._id)}
                                className="px-4 py-2 text-sm font-bold rounded-xl text-white shadow-sm hover:shadow-md transition-all hover:-translate-y-0.5 focus:ring-4 focus:ring-blue-200"
                                style={{ backgroundColor: PRIMARY_BLUE }}
                              >
                                Approve Tutor
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* General Admin Info / Placeholder */}
              <div className="bg-gradient-to-b from-white to-gray-50 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8 flex flex-col items-center justify-center text-center space-y-6">
                 <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500">
                    <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 002-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg>
                 </div>
                 <div>
                  <h3 className="text-xl font-bold text-gray-900">System Logs & Integrity</h3>
                  <p className="mt-2 text-gray-500 leading-relaxed max-w-sm">All backend systems are operating optimally. WebSocket server is actively broadcasting network load.</p>
                 </div>
                 <button className="px-6 py-3 bg-white border-2 border-gray-200 rounded-xl font-bold text-gray-700 hover:bg-gray-50 transition-colors w-full">
                   Generate Full Report
                 </button>
              </div>
            </section>

            {/* Payment Verifications */}
            <section className="bg-white rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 p-8">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-8 gap-4">
                <div>
                  <h2 className="text-xl font-bold text-gray-900">
                    Premium Subscriptions Verifications
                  </h2>
                  <p className="text-gray-500 mt-1">Review uploaded wire transfer receipts to grant premium access.</p>
                </div>
                <span className="inline-flex items-center px-4 py-2 rounded-full bg-blue-50 text-blue-700 font-bold text-sm">
                  {transactions.length} Transactions Pending
                </span>
              </div>

              {transactions.length === 0 ? (
                <div className="py-16 text-center bg-gray-50/50 rounded-2xl border-2 border-dashed border-gray-200">
                  <span className="text-5xl mb-4 block">🧾</span>
                  <p className="text-gray-500 font-medium text-lg">No pending payment verifications at this time.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                  {transactions.map((tx) => (
                    <div
                      key={tx._id}
                      className="group border-2 border-gray-100 rounded-2xl bg-white overflow-hidden flex flex-col hover:border-blue-200 hover:shadow-xl transition-all duration-300"
                    >
                      <div className="h-56 bg-gray-100 flex items-center justify-center overflow-hidden relative">
                        {/* Hover Overlay */}
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center z-10 backdrop-blur-sm">
                          <button 
                            type="button" 
                            onClick={() => window.open(tx.screenshotUrl, '_blank')}
                            className="px-6 py-2 bg-white text-gray-900 font-bold rounded-xl shadow-lg transform translate-y-4 group-hover:translate-y-0 transition-all"
                          >
                            View Full Size
                          </button>
                        </div>
                        {/* Screenshot image */}
                        <img
                          src={tx.screenshotUrl}
                          alt="Payment receipt"
                          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                        />
                      </div>
                      <div className="p-6 space-y-3 flex-1 flex flex-col">
                        <div className="flex-1">
                          <h3 className="font-bold text-lg text-gray-900 leading-tight">
                            {tx.student?.fullName || 'Unknown Student'}
                          </h3>
                          <div className="mt-3 space-y-2">
                            <p className="text-gray-600 flex items-center gap-2">
                              <span className="text-gray-400">🏫</span> 
                              Grade {tx.student?.grade || '—'} • {tx.student?.schoolName || 'N/A'}
                            </p>
                            <p className="text-gray-600 flex items-center gap-2">
                              <span className="text-gray-400">📱</span> 
                              {tx.student?.phone || 'No phone'}
                            </p>
                          </div>
                        </div>
                        <div className="pt-6 mt-4 border-t border-gray-100 flex flex-col gap-4">
                           <span className="inline-flex items-center gap-1.5 self-start rounded-full bg-yellow-100 px-3 py-1 text-sm font-bold text-yellow-800">
                             <div className="w-1.5 h-1.5 rounded-full bg-yellow-500"></div>
                             {tx.status}
                           </span>
                          <button
                            type="button"
                            onClick={() => handleApprovePremium(tx._id)}
                            className="w-full py-3 text-sm font-bold rounded-xl text-white shadow-md hover:shadow-lg transition-all hover:-translate-y-0.5 focus:ring-4 focus:ring-blue-200"
                            style={{ backgroundColor: PRIMARY_BLUE }}
                          >
                            Grant Premium Access
                          </button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        )}

        {activeTab === 'live' && (
          <section className="bg-gray-900 rounded-3xl shadow-2xl border border-gray-800 p-8 text-white min-h-[600px] flex flex-col animate-fade-in relative overflow-hidden">
            <div className="absolute top-0 right-0 w-96 h-96 bg-blue-500/10 blur-[100px] rounded-full pointer-events-none"></div>

            <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-8 gap-4 relative z-10">
              <div>
                <h2 className="text-2xl font-bold flex items-center gap-3">
                  <span className="relative flex h-4 w-4">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-4 w-4 bg-green-500"></span>
                  </span>
                  Live Network Monitoring
                </h2>
                <p className="text-gray-400 mt-2">Real-time WebSocket connection to Ethio Books message exchange cluster.</p>
              </div>
              <span className="inline-flex items-center px-4 py-2 rounded-xl bg-gray-800 text-gray-300 font-mono text-sm border border-gray-700">
                PINGS: {liveMessages.length} Packet(s)
              </span>
            </div>

            {liveMessages.length === 0 ? (
              <div className="flex-1 flex flex-col items-center justify-center text-gray-500 relative z-10 space-y-4 font-mono">
                <svg className="w-16 h-16 opacity-50 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"></path></svg>
                <p>Establishing secure socket connection...</p>
                <p className="text-sm">Listening for real-time events on port 5000.</p>
              </div>
            ) : (
              <div className="flex-1 overflow-y-auto pr-4 space-y-4 custom-scrollbar relative z-10">
                {liveMessages.map((msg, index) => (
                  <div
                    key={msg.id || index}
                    className="border-l-4 border-blue-500 bg-gray-800/80 rounded-r-xl p-5 hover:bg-gray-800 transition-colors backdrop-blur-sm"
                  >
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2 mb-3">
                      <div className="flex items-center flex-wrap gap-2 text-sm font-mono">
                        <span className="font-bold text-blue-400 bg-blue-400/10 px-2 py-1 rounded">
                          {msg.sender?.fullName || 'SYS_UNKNOWN'}
                        </span>
                        <span className="text-gray-500">➜</span>
                        <span className="font-bold text-purple-400 bg-purple-400/10 px-2 py-1 rounded">
                          {msg.receiver?.fullName || 'SYS_UNKNOWN'}
                        </span>
                      </div>
                      <span className="text-sm text-gray-500 font-mono tracking-wider bg-gray-900 px-3 py-1 rounded-lg">
                        {msg.timestamp
                          ? new Date(msg.timestamp).toLocaleTimeString()
                          : '00:00:00'}
                      </span>
                    </div>
                    <p className="text-gray-200 text-base leading-relaxed pl-2 font-mono">
                      &gt; {msg.text}
                    </p>
                    <div className="mt-4 pt-3 border-t border-gray-700/50 flex items-center justify-between text-xs text-gray-500 font-mono uppercase">
                      <span>Protocol: TPC/IP WSS</span>
                      <span>ENV_ID: {msg.roomId || 'GLOBAL_BROADCAST'}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </section>
        )}
      </main>

      {/* Global CSS overrides for the Admin Dashboard */}
      <style dangerouslySetInnerHTML={{__html: `
        .custom-scrollbar::-webkit-scrollbar {
          width: 8px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: rgba(31, 41, 55, 0.5);
          border-radius: 8px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: rgba(75, 85, 99, 1);
          border-radius: 8px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: rgba(107, 114, 128, 1);
        }
        .animate-fade-in {
          animation: fadeIn 0.4s ease-out forwards;
        }
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}} />
    </div>
  );
};

export default AdminDashboard;
